const https = require('https');

function makeRequest(options, postData = null) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          const parsed = JSON.parse(data);
          if (res.statusCode >= 200 && res.statusCode < 300) {
            resolve(parsed);
          } else {
            reject(new Error(`Notion API error (${res.statusCode}): ${parsed.message || data}`));
          }
        } catch (e) {
          reject(new Error(`Failed to parse response: ${e.message}`));
        }
      });
    });
    req.on('error', (err) => reject(err));
    if (postData) {
      req.write(postData);
    }
    req.end();
  });
}

const results = [];
const items = $input.all();

for (const item of items) {
  const { name, database_id, type, apiKey } = item.json;
  if (!database_id) continue;
  if (!apiKey) {
    throw new Error('NOTION_API_KEY is not defined in context. Ensure Set Notion API Key node is active.');
  }

  const headers = {
    'Authorization': `Bearer ${apiKey}`,
    'Notion-Version': '2022-06-28',
    'Content-Type': 'application/json'
  };

  try {
    if (type === 'page') {
      const options = {
        hostname: 'api.notion.com',
        path: `/v1/pages/${database_id}`,
        method: 'GET',
        headers
      };
      console.log(`Fetching Notion Page: ${name} (${database_id})`);
      const page = await makeRequest(options);
      results.push({
        ...page,
        database_id
      });
    } else {
      const options = {
        hostname: 'api.notion.com',
        path: `/v1/databases/${database_id}/query`,
        method: 'POST',
        headers
      };
      console.log(`Querying Notion Database: ${name} (${database_id})`);
      const dbResponse = await makeRequest(options, JSON.stringify({ page_size: 100 }));
      if (dbResponse.results && dbResponse.results.length > 0) {
        for (const page of dbResponse.results) {
          results.push({
            ...page,
            database_id
          });
        }
      }
    }
  } catch (error) {
    console.error(`Error fetching Notion resource ${name}:`, error.message);
  }
}

return results;

const results = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  if (!item.json.id) continue;

  let database_id = '';
  if (item.json.parent && item.json.parent.type === 'database_id') {
    database_id = item.json.parent.database_id;
  }

  if (!database_id) {
    try {
      database_id = item.json.database_id;
    } catch (e) {
      console.log('Could not get database_id from input item:', e.message);
    }
  }

  let title = '';
  if (item.json.properties) {
    for (const key of Object.keys(item.json.properties)) {
      const prop = item.json.properties[key];
      if (prop && prop.type === 'title') {
        if (prop.title && prop.title.length > 0) {
          title = prop.title.map(t => t.plain_text).join('');
        }
        break;
      }
    }
  }
  if (!title) {
    title = item.json.title || item.json.name || 'Untitled';
  }

  const url = item.json.url || '';
  const created_time = item.json.createdTime || item.json.created_time || new Date().toISOString();
  const last_edited_time = item.json.lastEditedTime || item.json.last_edited_time || new Date().toISOString();

  const properties = { ...item.json.properties };
  const content = JSON.stringify(properties);

  results.push({
    id: item.json.id,
    database_id,
    title,
    content,
    url,
    created_time,
    last_edited_time
  });
}
return results;
